data = input().split()

n = int(data[0])
k = int(data[1])

pebbles = list(map(int, data[2:]))

def can_paint(pebbles, k):
    max_pebbles = max(pebbles)
    if max_pebbles > k:
        return False

    colors = [defaultdict(list) for _ in range(k)]

    def assign_color(i, j, color):
        colors[color][i].append(j)

    def check():
        for color in range(k):
            for i in range(n):
                if len(colors[color][i]) > 1:
                    return False
        return True

    def backtrack(index):
        if index == n:
            return check()

        for color in range(max(0, pebbles[index] - 1), min(k, pebbles[index] + 2)):
            for j in range(pebbles[index]):
                assign_color(index, j, color)
                if backtrack(index + 1):
                    return True
                colors[color][index].pop()
        return False

    return backtrack(0)

if can_paint(pebbles, k):
    print("YES")
    for i in range(n):
        print(*colors[i][0])
else:
    print("NO")

