def can_paint(pebbles, k):
    max_pebbles = max(pebbles)
    if max_pebbles > k:
        return False

    colors = [defaultdict(list) for _ in range(k)]

    def assign_color(pile, index, color):
        colors[color][pile].append(index)

    def remove_color(pile, index, color):
        colors[color][pile].remove(index)

    def check():
        for color in range(k):
            for pile in range(n):
                if len(colors[color][pile]) > 1:
                    return False
        return True

    def backtrack(pile, current_color):
        if pile == n:
            return check()

        for color in range(current_color, k + 1):
            for i in range(len(pebbles[pile])):
                assign_color(pile, i, color)
                if backtrack(pile + 1, color):
                    return True
                remove_color(pile, i, color)

        return False

    return backtrack(0, 1)

if not can_paint(pebbles, k):
    print("NO")
else:
    print("YES")
