def can_paint(pebbles, k):
    max_pebbles = max(pebbles)
    if max_pebbles > k:
        return False

    colors = [defaultdict(list) for _ in range(k)]

    def assign_color(i, j, color):
        colors[color][i].append(j)

    def check():
        for i in range(n):
            for j in range(len(colors)):
                if len(colors[j][i]) > 1:
                    return False
        return True

    def backtrack(index):
        if index == n:
            return check()

        for color in range(max_pebbles + 1):
            for j in range(pebbles[index]):
                assign_color(index, j, color)
                if backtrack(index + 1):
                    return True
                colors[color][index] = []
        return False

    return backtrack(0)

