class Solution:
    def __init__(self):
        self.index = 0

    def read_int(self):
        val = int(data[self.index])
        self.index += 1
        return val

    def read_tuple(self):
        return tuple(map(int, data[self.index:self.index+3]))
        self.index += 3

    def can_satisfy_customers(self, n, m, customers):
        current_time = 0
        current_temp = m
        heating_times = []
        cooling_times = []

        for t, l, h in customers:
            while current_time < t:
                if not heating_times and not cooling_times:
                    current_temp += 1
                    current_time += 1
                elif heating_times and current_time < heating_times[0]:
                    current_temp += 1
                    current_time += 1
                elif cooling_times and current_time < cooling_times[0]:
                    current_temp -= 1
                    current_time += 1
                else:
                    break

            if l <= current_temp <= h:
                continue

            if current_temp < l:
                if not heating_times or heating_times[-1] <= current_time:
                    heating_times.append(current_time)
                    current_temp += 1
                    current_time += 1
                else:
                    return False
            else:
                if not cooling_times or cooling_times[-1] <= current_time:
                    cooling_times.append(current_time)
                    current_temp -= 1
                    current_time += 1
                else:
                    return False

        return True

    def solve(self):
        q = self.read_int()
        results = []

        for _ in range(q):
            n = self.read_int()
            m = self.read_int()
            customers = [self.read_tuple() for _ in range(n)]

            if self.can_satisfy_customers(n, m, customers):
                results.append("YES")
            else:
                results.append("NO")

        for result in results:
            print(result)

# Create and run the solution
