def can_assign_degrees(expected):
    # Create a dictionary to count occurrences of each degree
    degree_count = defaultdict(int)
    for d in degrees:
        degree_count[d] += 1

    # Try to assign degrees to match the expected values
    assigned = [-1] * n
    used = set()

    for i in range(n):
        if assigned[i] != -1:
            continue

        target = expected[i]
