from collections import defaultdict

def parse_input():
    input = sys.stdin.read
    data = input().split()
    n = int(data[0])
    m = int(data[1])
    variables = {}
    index = 2
    for _ in range(n):
        var_name = data[index]
        index += 1
        op = data[index]
        index += 1
        if op == ':=':
            value = data[index]
            index += 1
            variables[var_name] = value
        else:
            left = data[index]
            index += 1
            right = data[index]
            index += 1
            variables[var_name] = (op, left, right)
    return n, m, variables

def evaluate(variables, choice):
    stack = []
    for key, value in variables.items():
        if isinstance(value, str):
            stack.append(int(value, 2))
        else:
            op, left, right = value
            if left == '?':
                left_val = choice
            else:
                left_val = stack.pop()
            if right == '?':
                right_val = choice
            else:
                right_val = stack.pop()
            if op == 'AND':
                stack.append(left_val & right_val)
            elif op == 'OR':
                stack.append(left_val | right_val)
            elif op == 'XOR':
                stack.append(left_val ^ right_val)
    return sum(stack)

def find_min_max_scores(n, m, variables):
    min_score = float('inf')
    max_score = -float('inf')
    min_choice = None
    max_choice = None

    for i in range(2**m):
        score = evaluate(variables, i)
        if score < min_score:
            min_score = score
            min_choice = i
        if score > max_score:
            max_score = score
            max_choice = i

    return min_choice, max_choice

def main():
