def process_test_case(N, M, H, moves):
    time = 0
    current_floor = [1] * M
    queue = []

    for i in range(N):
        start, end = moves[i]
        queue.append((start, end))

    while queue:
        next_queue = []
        for start, end in queue:
            if start == end:
                continue
            found_elevator = False
            for j in range(M):
                if current_floor[j] <= start:
                    current_floor[j] = start + 1
                    found_elevator = True
                    break
            if found_elevator:
                next_queue.append((end, end))
            else:
                next_queue.append((start, end))

        time += 1
        for j in range(M):
            if current_floor[j] > 1:
                current_floor[j] -= 1

        queue = next_queue

    return time * (H + 1)

