class Solution:
    def min_time(self, n, m, h, moves):
        time = 0
        current_floor = [1] * m
        while True:
            done = True
            for i in range(n):
                a, b = moves[i]
                if current_floor[moves[i][2]] >= b:
                    continue
                done = False
                found = False
                for j in range(m):
                    if current_floor[j] == a:
                        current_floor[j] = b
                        moves[i].append(j)
                        found = True
                        break
                if not found:
                    for j in range(m):
                        if current_floor[j] < a:
                            current_floor[j] += (b - a + 1)
                            moves[i].append(j)
                            found = True
                            break
                if not found:
                    return float('inf')
            if done:
                break
            time += max(1, max(current_floor) - 1)
        return time + n * h

