MOD = 998244353

def pow_mod(x, y):
    res = 1
    while y:
        if y & 1:
            res = res * x % MOD
        x = x * x % MOD
        y >>= 1
    return res

def inv_mod(x):
    return pow_mod(x, MOD - 2)

def comb(n, r):
    if r > n:
        return 0
    num = den = 1
    for i in range(r):
        num = num * (n - i) % MOD
        den = den * (i + 1) % MOD
    return num * inv_mod(den) % MOD

def solve(n, k):
    if n == 1:
        return 1
    if k == 1:
        return 1
    dp = [0] * (n + 1)
    dp[1] = 1
    dp[2] = 2
    for i in range(3, n + 1):
        dp[i] = (dp[i - 1] + dp[i - 2]) % MOD
    ans = 0
    for i in range(1, n + 1):
        ans = (ans + comb(n, i) * dp[i]) % MOD
    return ans

