import sys

def lcs(s1, s2, virus):
    m, n = len(s1), len(s2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s1[i - 1] == s2[j - 1]:
                dp[i][j] = dp[i - 1][j - 1] + 1
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    def reconstruct_lcs(i, j):
        if i == 0 or j == 0:
            return ""
        elif s1[i - 1] == s2[j - 1]:
            return reconstruct_lcs(i - 1, j - 1) + s1[i - 1]
        elif dp[i - 1][j] > dp[i][j - 1]:
            return reconstruct_lcs(i - 1, j)
        else:
            return reconstruct_lcs(i, j - 1)

    lcs_str = reconstruct_lcs(m, n)

    while virus in lcs_str:
        lcs_str = lcs_str.replace(virus, "")

    return lcs_str if lcs_str else "0"

