input = sys.stdin.read
data = input().split()

n = int(data[0])
r1, c1 = map(int, data[1:3])
r2, c2 = map(int, data[3:5])

grid = []
for i in range(n):
    grid.append(list(map(int, data[5 + i])))

def bfs(start, end):
    queue = deque([start])
    visited = set([start])
    while queue:
        x, y = queue.popleft()
        if (x, y) == end:
            return True
        for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nx, ny = x + dx, y + dy
            if 1 <= nx <= n and 1 <= ny <= n and grid[nx-1][ny-1] == 0 and (nx, ny) not in visited:
                visited.add((nx, ny))
                queue.append((nx, ny))
    return False

if bfs((r1, c1), (r2, c2)):
    print(0)
else:
    min_cost = float('inf')
    for i in range(1, n+1):
        for j in range(1, n+1):
            if grid[i-1][j-1] == 0:
                for k in range(1, n+1):
                    for l in range(1, n+1):
                        if grid[k-1][l-1] == 0 and (i, j) != (k, l):
                            cost = (i-k)**2 + (j-l)**2
                            if bfs((r1, c1), (i, j)) and bfs((i, j), (k, l)) and bfs((k, l), (r2, c2)):
                                min_cost = min(min_cost, cost)
    print(min_cost)

