    for neighbor in graph[node]:
        if neighbor != parent:
            size = dfs(neighbor, node, graph)
            if size > 0:
                subtree_sizes.append(size)
    if len(subtree_sizes) == 0:
        return 1
    elif len(subtree_sizes) == 1:
        if is_fibonacci(subtree_sizes[0]):
            return subtree_sizes[0]
    else:
        sorted_sizes = sorted(subtree_sizes)
        if is_fibonacci(sorted_sizes[-1] + sorted_sizes[-2]) and is_fibonacci(sorted_sizes[-1]):
            return sum(sorted_sizes)
    return -1

