import sys
from collections import defaultdict, deque

def is_fibonacci(n):
    a, b = 0, 1
    while a < n:
        a, b = b, a + b
    return a == n

def find_fib_trees(graph, root):
    stack = [(root, None)]
    fib_trees = []

    while stack:
        node, parent = stack.pop()
        children = [child for child in graph[node] if child != parent]

        if len(children) == 0:
            fib_trees.append(1)
        elif len(children) == 1:
            child = children[0]
            left_size = find_fib_trees(graph, child)
            if left_size > 0 and is_fibonacci(left_size + 1):
                fib_trees.append(left_size + 1)
        else:
            left_child, right_child = children[:2]
            left_size = find_fib_trees(graph, left_child)
            right_size = find_fib_trees(graph, right_child)

            if left_size > 0 and right_size > 0 and is_fibonacci(left_size + right_size + 1):
                fib_trees.append(left_size + right_size + 1)

    return sum(fib_trees)

