from collections import defaultdict, deque

def is_fibonacci(n):
    a, b = 0, 1
    while a < n:
        a, b = b, a + b
    return a == n

def find_fib_trees(n, edges):
    def dfs(node, parent):
        nonlocal fib_trees
        subtree_sizes = [1]
        for neighbor in adj[node]:
            if neighbor != parent:
                child_size = dfs(neighbor, node)
                subtree_sizes.append(child_size)
                if is_fibonacci(child_size):
                    fib_trees.add(child_size)
        total_size = sum(subtree_sizes)
        if is_fibonacci(total_size):
            fib_trees.add(total_size)
        return total_size

    adj = defaultdict(list)
    for u, v in edges:
        adj[u].append(v)
        adj[v].append(u)

    fib_trees = set()
    dfs(1, -1)
    return len(fib_trees) > 0

