def min_operations(n, k, points):
    if n == 1:
        return 0

    def can_move_to(target_x, target_y):
        visited = set()
        queue = [target_x]
        while queue:
            current_x = queue.pop(0)
            if (current_x, target_y) in visited:
                continue
            visited.add((current_x, target_y))
            for i in range(n):
                if (points[i][0], points[i][1]) == (current_x, target_y):
                    continue
                if manhattan_distance(current_x, target_y, points[i][0], points[i][1]) <= k:
                    queue.append(points[i][0])
        return len(visited) == n

    for i in range(n):
        for j in range(i+1, n):
            if manhattan_distance(points[i][0], points[i][1], points[j][0], points[j][1]) > 2 * k:
                return -1

    for i in range(n):
        for j in range(i+1, n):
            if manhattan_distance(points[i][0], points[i][1], points[j][0], points[j][1]) <= 2 * k:
                target_x = (points[i][0] + points[j][0]) // 2
                target_y = (points[i][1] + points[j][1]) // 2
                if can_move_to(target_x, target_y):
                    return 1

    return -1

