from collections import defaultdict, deque

input = sys.stdin.read
data = input().split()

n = int(data[0])
m = int(data[1])
elements = list(map(int, data[2:]))

graph = defaultdict(list)

for x in elements:
    for y in elements:
        if x & y == 0:
            graph[x].append(y)
            graph[y].append(x)

visited = set()
components = 0

for x in elements:
    if x not in visited:
        queue = deque([x])
        while queue:
            node = queue.popleft()
            if node not in visited:
                visited.add(node)
                for neighbor in graph[node]:
                    queue.append(neighbor)
        components += 1

