k = int(data[2])

participants = []
for i in range(m):
    l = int(data[3 + 2 * i]) - 1
    r = int(data[4 + 2 * i]) - 1
    participants.append((l, r))

max_sum = 0

for start1 in range(n - k + 1):
    end1 = start1 + k - 1
    count1 = 0
    for l, r in participants:
        if max(l, start1) <= min(r, end1):
            count1 += min(r, end1) - max(l, start1) + 1

    for start2 in range(n - k + 1):
        if start2 == start1:
            continue
        end2 = start2 + k - 1
        count2 = 0
        for l, r in participants:
            if max(l, start2) <= min(r, end2):
                count2 += min(r, end2) - max(l, start2) + 1

        total_count = max(count1, count2)
        if total_count > max_sum:
            max_sum = total_count

print(max_sum)

MOD = 10**9 + 7

def count_random_pictures(n, m):
    if n == 1:
        return pow(2, m, MOD)
    if m == 1:
        return pow(2, n, MOD)

    dp = [[0] * (m + 1) for _ in range(n + 1)]
    dp[1][1] = 2

    for i in range(1, n + 1):
        for j in range(1, m + 1):
            if i == 1 and j == 1:
                continue
            dp[i][j] = (dp[i-1][j] + dp[i][j-1]) % MOD

    return dp[n][m]

