def count_ways(n, s):
    def catalan_number(k):
        if k <= 1:
            return 1
        c = [0] * (k + 1)
        c[0], c[1] = 1, 1
        for i in range(2, k + 1):
            c[i] = sum(c[j] * c[i - j - 1] for j in range(i)) % MOD
        return c[k]

    def dp(s):
        stack = []
        for char in s:
            if char == '(':
                stack.append(char)
            else:
                if stack and stack[-1] == '(':
                    stack.pop()
                else:
                    return 0
        return len(stack)

    open_needed = dp(s)
    close_needed = len(s) - open_needed
    if open_needed > n or close_needed > n:
        return 0

    ways_to_balance_open = catalan_number(open_needed)
    ways_to_balance_close = catalan_number(close_needed)
    total_ways = (ways_to_balance_open * ways_to_balance_close) % MOD
    return total_ways

