def count_ways(n, s):
    m = len(s)
    dp = [[0] * (m + 1) for _ in range(m + 1)]
    dp[0][0] = 1

    for i in range(m + 1):
        for j in range(i + 1):
            if i > 0:
                dp[i][j] += dp[i - 1][j]
                dp[i][j] %= MOD
            if j > 0 and j <= i:
                dp[i][j] += dp[i][j - 1]
                dp[i][j] %= MOD
            if i > 0 and j > 0 and s[j - 1] == ')':
                dp[i][j] -= dp[i - 1][j - 1]
                dp[i][j] += MOD
                dp[i][j] %= MOD

    total_ways = dp[m][m]

    def is_valid(seq):
        balance = 0
        for char in seq:
            if char == '(':
                balance += 1
            else:
                balance -= 1
            if balance < 0:
                return False
        return balance == 0

    def count_subsequences(seq, target):
        m = len(target)
        dp = [0] * (m + 1)
        dp[0] = 1

        for char in seq:
            for j in range(m, 0, -1):
                if char == target[j - 1]:
                    dp[j] += dp[j - 1]
                    dp[j] %= MOD

        return dp[m]

    valid_sequences = 0
    for i in range(n - m + 1):
        left_seq = ')' * i
        right_seq = '(' * (n - m - i)
        subseq_count = count_subsequences(left_seq + s + right_seq, s)
        valid_sequences += subseq_count
        valid_sequences %= MOD

    return (total_ways * valid_sequences) % MOD

