            if i > 0 and j > 0 and s[j - 1] == ')':
                dp[i][j] -= dp[i - 1][j - 1]
                dp[i][j] += MOD
                dp[i][j] %= MOD

    total_ways = dp[m][m]

    def balance_brackets(subseq):
        stack = []
        for char in subseq:
            if char == '(':
                stack.append(char)
            elif char == ')' and stack:
                stack.pop()
        return len(stack)

    left_balance = balance_brackets(s)
    right_balance = balance_brackets(s[::-1])

    result = 0
    for k in range(left_balance + 1):
        if (left_balance - k) % 2 == 0:
            result += dp[k][k]
            result %= MOD

    for k in range(right_balance + 1):
        if (right_balance - k) % 2 == 0:
            result += dp[k][k]
            result %= MOD

    return (total_ways * result) % MOD

