    dp[0][0] = 1

    for i in range(2 * n):
        new_dp = [[0] * (m + 1) for _ in range(m + 1)]
        for j in range(m + 1):
            for k in range(j + 1):
                if i % 2 == 0:
                    new_dp[j][k] += dp[j][k]
                    if j > 0:
                        new_dp[j - 1][k] += dp[j][k]
                else:
                    if k < m:
                        new_dp[j][k + 1] += dp[j][k]
                    if j > 0 and k < m:
                        new_dp[j - 1][k + 1] += dp[j][k]

        for j in range(m + 1):
            for k in range(j + 1):
                if j >= len(s) or k != ord(s[j]) - ord('0'):
                    continue
                new_dp[j][k] += dp[j][k]
                if j > 0:
                    new_dp[j - 1][k] += dp[j][k]

        dp = new_dp

    return sum(dp[j][j // 2] for j in range(m + 1)) % MOD

