def preprocess_f_values(gcds, n):
    f_values = [0] * (n+1)
    for i in range(1, n+1):
        for divisor, count in gcds[i].items():
            f_values[i] += divisor * count
    return f_values

def query_sum(f_values, prefix_sums, x, y):
    return (prefix_sums[y] - prefix_sums[x-1]) % MOD

def update_value(f_values, prefix_sums, index, old_value, new_value, gcds):
    for divisor, count in gcds[old_value].items():
        f_values[index] -= divisor * count
    for divisor, count in gcds[new_value].items():
        f_values[index] += divisor * count
    prefix_sums[index] = prefix_sums[index-1] + f_values[index]

