from typing import List

def orientation(p: List[int], q: List[int], r: List[int]) -> int:
    val = (q[1] - p[1]) * (r[0] - q[0]) - (q[0] - p[0]) * (r[1] - q[1])
    if val == 0:
        return 0
    elif val > 0:
        return 1
    else:
        return 2

def is_convex(points: List[List[int]]) -> bool:
    n = len(points)
    if n < 3:
        return False
    prev_orientation = None
    for i in range(n):
        p = points[i]
        q = points[(i + 1) % n]
        r = points[(i + 2) % n]
        orient = orientation(p, q, r)
        if orient != 0:
            if prev_orientation is not None and prev_orientation != orient:
                return False
            prev_orientation = orient
    return True

def find_permutation(points: List[List[int]]) -> List[int]:
    n = len(points)
    if not is_convex(points):
        return [-1]

    def dfs(path: List[int], visited: List[bool]) -> bool:
        if len(path) == n:
            return True
        for i in range(n):
            if not visited[i]:
                p = path[-1]
                q = points[i]
                r = points[(path[-2] if len(path) > 1 else -1)]
                if orientation(q, r, p) == 1:
                    visited[i] = True
                    path.append(i)
                    if dfs(path, visited):
                        return True
                    path.pop()
                    visited[i] = False
        return False

    for i in range(n):
        visited = [False] * n
        visited[i] = True
        path = [i]
        if dfs(path, visited):
            return [points.index(points[j]) + 1 for j in path]
    return [-1]

