from typing import List

def orientation(p: List[int], q: List[int], r: List[int]) -> int:
    val = (q[1] - p[1]) * (r[0] - q[0]) - (q[0] - p[0]) * (r[1] - q[1])
    if val == 0:
        return 0
    elif val > 0:
        return 1
    else:
        return 2

def is_convex(points: List[List[int]]) -> bool:
    n = len(points)
    if n < 3:
        return False
    prev_orientation = None
    for i in range(n):
        p = points[i]
        q = points[(i + 1) % n]
        r = points[(i + 2) % n]
        current_orientation = orientation(p, q, r)
        if current_orientation != 0:
            if prev_orientation is not None and prev_orientation != current_orientation:
                return False
            prev_orientation = current_orientation
    return True

def find_permutation(points: List[List[int]]) -> List[int]:
    n = len(points)
    if not is_convex(points):
        return [-1]

    def dfs(index: int, path: List[int], visited: List[bool]):
        if index == n:
            return path

        for i in range(n):
            if not visited[i]:
                visited[i] = True
                new_path = dfs(index + 1, path + [i + 1], visited)
                if new_path:
                    return new_path
                visited[i] = False

    visited = [False] * n
    return dfs(0, [], visited)

