input = sys.stdin.read
data = input().split()

N = int(data[0])
Q = int(data[1])

class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.size = [1] * n
        self.index = list(range(1, n + 1))

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        root_x = self.find(x)
        root_y = self.find(y)
        if root_x != root_y:
            if self.size[root_x] < self.size[root_y]:
                root_x, root_y = root_y, root_x
            self.parent[root_y] = root_x
            self.size[root_x] += self.size[root_y]
            self.index[root_x] = self.index[root_x] + self.index[root_y] + 1

def main():
    uf = UnionFind(N + 1)
    result = []
    index = 0
    for i in range(2, 2 * Q + 1, 2):
        query_type = data[i]
        if query_type == "UNION":
            a = int(data[i + 1]) - 1
            b = int(data[i + 2]) - 1
            uf.union(a, b)
        elif query_type == "GET":
            a = int(data[i + 1]) - 1
            k = int(data[i + 2])
            root_a = uf.find(a)
            result.append(uf.index[root_a] - k + 1)
    for r in result:
        print(r)

if __name__ == "__main__":
    main()

